import{_ as l,p as i,q as e,a1 as a}from"./framework-822ca1a4.js";const r={},s=a('<h1 id="一般现在时" tabindex="-1"><a class="header-anchor" href="#一般现在时" aria-hidden="true">#</a> 一般现在时</h1><p>用法：</p><ol><li>当表示经常型，习惯性，有规律性的动作和状态的时候。</li><li>当表示真理性，客观性的动作和状态。</li><li>不轻易改变的状态。</li><li>表示此时此刻的状态。</li></ol><h2 id="主系表" tabindex="-1"><a class="header-anchor" href="#主系表" aria-hidden="true">#</a> 主系表</h2><p>主系表分为以下四个句型:</p><ol><li>人称代词主格 + is/are/am + 形容词</li></ol><ul><li>I am happy.</li><li>You are happy.</li><li>She is happy.</li><li>He is busy.</li><li>It is cheap.</li><li>We are famous.</li><li>They are busy.</li></ul><ol start="2"><li>名词 + is/are + 形容词</li></ol><ul><li>Nick is busy.</li><li>Beijing is big.</li><li>Nick and Jack are busy.</li><li>The student is happy.</li><li>My house is big.</li><li>Teachers are busy.</li><li>The teachers are busy.</li><li>Water is important.</li><li>The water is important.</li></ul><ol start="3"><li>人称代词主格 + is/are/am + 名词</li></ol><ul><li>I am a student.</li><li>You are teacher.</li><li>She is a nurse .</li><li>He is my teacher.</li><li>It is my room.</li><li>We are actors.</li><li>They are her books.</li></ul><ol start="4"><li>名词 + is/are + 名词</li></ol><ul><li>Nick is a teacher.</li><li>My teacher is Nick.</li><li>His father is a farmer.</li><li>The doctor is my brother.</li><li>Nick&#39;s students are bosses.</li></ul><p>变否定句</p><ul><li>I&#39;m not a teacher.</li><li>The book isn&#39;t cheap.</li><li>You aren&#39;t a teacher.</li><li>His father isn&#39;t a farmer.</li></ul><p>变一般疑问句</p><ul><li>Is she pretty?</li><li>Are you a teacher?</li></ul><h2 id="主谓宾" tabindex="-1"><a class="header-anchor" href="#主谓宾" aria-hidden="true">#</a> 主谓宾</h2><p>主谓宾，分为以下四个句型:</p><ol><li>主语 + 不及物动词</li><li>主语 + 及物动词 + 宾语</li><li>主语 + 双宾动词 + 间接宾语 + 直接宾语</li><li>主语 + 及物动词 + 宾语 + 宾补</li></ol><p>主谓宾的句型的主语又分为两种情况，第三人称单数和非第三人称单数，他们对应的谓语动词会有所不同，下面分来来讲。</p><h3 id="非第三人称单数" tabindex="-1"><a class="header-anchor" href="#非第三人称单数" aria-hidden="true">#</a> 非第三人称单数</h3><ol><li>I/We/You/They + 不及物动词原型 + 状语</li></ol><ul><li>I sleep every day.</li><li>We work every day.</li><li>You cry every day.</li><li>They walk every day.</li></ul><ol start="2"><li>名词复数 + 不及物动词原型 + 状语</li></ol><ul><li>My friends work every day.</li><li>Nick&#39;s classmates run every day.</li><li>The nurses work every day.</li><li>My daughters cry every day.</li><li>Nick and Jack work every day.</li></ul><ol start="3"><li>I/We/You/They + 及物动词原型 + 宾语 + 状语</li></ol><ul><li>I bake potatoes every day.</li><li>We eat apples every day.</li><li>You buy a book every day.</li><li>They drink water every day.</li></ul><ol start="4"><li>名词复数 + 及物动词原型 + 宾语 + 状语</li></ol><ul><li>My friends bake potatoes every day.</li><li>Her classmates buy books every day.</li><li>Nick&#39;s fans trust him.</li><li>The secretaries drink coffee every day.</li><li>These girls like KUN.</li></ul><p>变一般疑问句，直接在句首加助动词“do”，句尾加问号就可以了。</p><ul><li>Do they walk every day?</li><li>Do you work every day?</li><li>Do the secretaries?</li></ul><p>变否定句，在谓语动词原型前面加助动词“do”的否定格式“do not”或者缩写格式“don&#39;t”。</p><ul><li>I don&#39;t read books every day.</li><li>These girls don&#39;t lick KUN.</li><li>Nick&#39;s fans don&#39;t trust him.</li></ul><h3 id="第三人称单数" tabindex="-1"><a class="header-anchor" href="#第三人称单数" aria-hidden="true">#</a> 第三人称单数</h3><p>当主语是第三人称单数的时候，谓语动词就需要变成第三人称单数的格式。属于第三人称单数的主句有：</p><ol><li>人称代词主格：she，he，it</li><li>所有的名词单数，例如：train，bus，father，doctor</li><li>一个人名或地名，例如：Nick，London</li><li>不可数名词，例如：water，wine</li><li>指示代词：this，that</li><li>动词不定式和动名词短语</li><li>主语从句</li></ol><p>单三的四个句型（动词需要用第三人称单数格式）：</p><ol><li>She/He/It + 不及物动词 + 状语</li></ol><ul><li>She bathes every day.</li><li>He works every day.</li><li>It sleeps every day.</li></ul><ol start="2"><li>名词单数 + 不及物动词 + 状语</li></ol><ul><li>My friends works every day.</li><li>The nurse bathes every day.</li><li>This girl smiles every day.</li><li>Nick runs every day.</li></ul><ol start="3"><li>She/He/It + 及物动词 + 宾语 + 状语</li></ol><ul><li>She cooks noodles every day.</li><li>He drinks tea every day.</li><li>It eats pork every day.</li></ul><ol start="4"><li>名词单数 + 及物动词 + 宾语 + 状语</li></ol><ul><li>My friends eats a banana every day.</li><li>Nick&#39;s leader likes the car.</li><li>This girl drinks coffee every day.</li><li>Jack reads my book every day.</li></ul><p>变一般疑问句，句首加助动词“does”，句尾加问号，并把谓语动词变回原型。</p><ul><li>Does she like flowers?</li><li>Does your leader believe you?</li></ul><p>变否定句，谓语动词前面加助动词“does”的否定格式“doesn&#39;t”，把谓语动词变回原型。</p><ul><li>She doesn&#39;t like flowers.</li><li>My leader doesn&#39;t believe me.</li></ul><h2 id="时间状语" tabindex="-1"><a class="header-anchor" href="#时间状语" aria-hidden="true">#</a> 时间状语</h2><ol><li>every + 表示时间的名词单数</li></ol><p>表示时间的名词有：</p><p>second 秒 / minute 分钟 / hour 小时 / morning 早上</p><p>noon 中午 / afternoon 下午 / evening 晚上 / night 夜晚</p><p>day 天 / year 天 / week 周 / month 月 / season 季度</p><ol start="2"><li>频度副词</li></ol><p>always 总是 / often 经常 / usually 通常 / something 有时候</p><p>seldom 很少 / occasionally 偶尔 / never 从不</p>',59),o=[s];function t(y,d){return i(),e("div",null,o)}const n=l(r,[["render",t],["__file","present-tense.html.vue"]]);export{n as default};
